parameters.jsCode:
const testPaper = $input.first().json.output.test_paper;

let content = `${testPaper.metadata.title}\n`;
content += `${'='.repeat(testPaper.metadata.title.length)}\n\n`;
content += `Subject: ${testPaper.metadata.subject}\n`;
content += `Topics: ${testPaper.metadata.topics.join(', ')}\n`;
content += `Duration: ${testPaper.metadata.duration_minutes} minutes | Total Marks: ${testPaper.metadata.total_marks}\n\n`;

content += `INSTRUCTIONS:\n`;
content += `${testPaper.instructions}\n\n`;

content += `QUESTIONS:\n`;
content += `${'-'.repeat(50)}\n\n`;

testPaper.questions.forEach(q => {
  content += `${q.question_number}. ${q.question_text}\n`;
  content += `   [${q.marks} marks] [Difficulty: ${q.difficulty}] [Topic: ${q.topic}]\n\n`;
});

content += `\n${'='.repeat(50)}\n`;
content += `SUMMARY:\n`;
content += `Total Questions: ${testPaper.metadata.total_questions}\n`;
content += `Easy: ${testPaper.metadata.difficulty_distribution.easy} questions\n`;
content += `Medium: ${testPaper.metadata.difficulty_distribution.medium} questions\n`;
content += `Hard: ${testPaper.metadata.difficulty_distribution.hard} questions\n`;

return {
  json: {
    title: testPaper.metadata.title,
    content: content
  }
};

